import 'package:flutter/material.dart'; import '../main.dart'; import 'package:adhan/adhan.dart'; import 'package:geolocator/geolocator.dart'; class PrayerQiblaScreen extends StatefulWidget { @override _P createState()=>_P(); } class _P extends State<PrayerQiblaScreen> { String txt='جاري تحديد الموقع...'; @override void initState(){ super.initState(); _load(); } _load() async { try{ var perm=await Geolocator.checkPermission(); if(perm==LocationPermission.denied) perm=await Geolocator.requestPermission(); var pos=await Geolocator.getCurrentPosition(); var params=CalculationMethod.muslim_world_league.getParameters(); params.madhab=Madhab.shafi; var times=PrayerTimes.today(Coordinates(pos.latitude, pos.longitude), params); setState(()=>txt='الفجر: \${times.fajr}\nالظهر: \${times.dhuhr}\nالعصر: \${times.asr}\nالمغرب: \${times.maghrib}\nالعشاء: \${times.isha}\n\nالقبلة: \${Qibla(Coordinates(pos.latitude, pos.longitude)).direction.toStringAsFixed(1)}°'); }catch(e){ setState(()=>txt='خطأ: \$e'); } } @override Widget build(BuildContext context){ return WatermarkScaffold(title: 'القبلة والصلاة', child: Padding(padding: EdgeInsets.all(20), child: Text(txt, style: TextStyle(fontSize:18, height:1.8)))); } }